package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserTest {

    private static final CSVFormat MOCK_FORMAT = mock(CSVFormat.class);

    @BeforeEach
    void setUp() {
        // Reset mocks before each test if needed
        Mockito.reset(MOCK_FORMAT);
    }

    @Test
    void parse_NullString_ThrowsNullPointerException() {
        NullPointerException exception = assertThrows(NullPointerException.class,
                () -> CSVParser.parse((String) null, MOCK_FORMAT));
        assertEquals("string", exception.getMessage());
    }

    @Test
    void parse_NullFormat_ThrowsNullPointerException() {
        NullPointerException exception = assertThrows(NullPointerException.class,
                () -> CSVParser.parse("data", null));
        assertEquals("format", exception.getMessage());
    }

    @Test
    void parse_ValidStringAndFormat_ReturnsCSVParser() throws IOException, NoSuchFieldException, IllegalAccessException {
        String input = "header1,header2\nvalue1,value2";
        CSVParser parser = CSVParser.parse(input, MOCK_FORMAT);
        assertNotNull(parser);
        // Because constructor uses StringReader, the internal reader should not be null
        assertFalse(parser.isClosed());

        // Use reflection to access private field 'format'
        Field formatField = CSVParser.class.getDeclaredField("format");
        formatField.setAccessible(true);
        CSVFormat actualFormat = (CSVFormat) formatField.get(parser);
        assertEquals(MOCK_FORMAT, actualFormat);

        // Use reflection to access private field 'record'
        Field recordField = CSVParser.class.getDeclaredField("record");
        recordField.setAccessible(true);
        List<?> recordList = (List<?>) recordField.get(parser);
        assertNotNull(recordList);
        assertEquals(0, recordList.size());
    }
}
